import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';

const BusTracking = () => {
  const [booking, setBooking] = useState(null);
  const [busLocation, setBusLocation] = useState(null);
  const [trackingStatus, setTrackingStatus] = useState('active');
  const [estimatedArrival, setEstimatedArrival] = useState('');
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    const bookingData = location.state?.booking;
    if (bookingData) {
      setBooking(bookingData);
      startTracking(bookingData);
    } else {
      // Try to get recent booking from localStorage
      const recentBooking = getRecentBooking();
      if (recentBooking) {
        setBooking(recentBooking);
        startTracking(recentBooking);
      } else {
        navigate('/user-dashboard');
      }
    }
  }, [location.state, navigate]);

  const getRecentBooking = () => {
    // Mock recent booking
    return {
      id: 'BK123456',
      busName: 'Express Travels',
      busType: 'AC Sleeper',
      route: 'New York → Los Angeles',
      date: '2024-04-15',
      departure: '08:00 AM',
      arrival: '02:00 PM',
      seats: ['12', '13'],
      totalAmount: 900,
      status: 'Confirmed',
      bookingDate: '2024-04-01'
    };
  };

  const startTracking = (bookingData) => {
    // Simulate real-time tracking
    const waypoints = [
      { location: 'New York Bus Terminal', time: '08:00 AM', status: 'Departed' },
      { location: 'Newark', time: '08:45 AM', status: 'Passed' },
      { location: 'Philadelphia', time: '10:30 AM', status: 'Passed' },
      { location: 'Baltimore', time: '12:00 PM', status: 'Current' },
      { location: 'Washington DC', time: '01:00 PM', status: 'Upcoming' },
      { location: 'Los Angeles Bus Terminal', time: '02:00 PM', status: 'Destination' }
    ];

    setBusLocation({
      currentLocation: 'Baltimore',
      nextStop: 'Washington DC',
      progress: 65,
      speed: 65,
      waypoints: waypoints
    });

    // Calculate estimated arrival
    const now = new Date();
    const arrivalTime = new Date(now.getTime() + 60 * 60 * 1000); // 1 hour from now
    setEstimatedArrival(arrivalTime.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }));
  };

  const handleRefresh = () => {
    // Simulate refresh
    setBusLocation(prev => ({
      ...prev,
      progress: Math.min(prev.progress + 5, 95),
      speed: 60 + Math.floor(Math.random() * 10)
    }));
  };

  const handleShareLocation = () => {
    if (navigator.share) {
      navigator.share({
        title: 'Bus Tracking',
        text: `Track my bus ${booking?.busName} - Current location: ${busLocation?.currentLocation}`,
        url: window.location.href
      });
    } else {
      alert('Location shared successfully!');
    }
  };

  const handleCallDriver = () => {
    alert('Calling driver... +1-234-567-8900');
  };

  const handleEmergencyContact = () => {
    alert('Emergency contact: +1-800-BUS-HELP');
  };

  if (!booking || !busLocation) {
    return <div>Loading tracking information...</div>;
  }

  return (
    <div className="container">
      <div className="card">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <h2>Bus Tracking</h2>
          <div>
            <button className="btn btn-secondary" onClick={handleRefresh} style={{ marginRight: '10px' }}>
              🔄 Refresh
            </button>
            <button className="btn btn-secondary" onClick={handleShareLocation}>
              📤 Share
            </button>
          </div>
        </div>

        <div className="card" style={{ background: '#f8f9fa', marginBottom: '20px' }}>
          <h3>{booking.busName}</h3>
          <p>{booking.busType} | {booking.route}</p>
          <p><strong>Booking ID:</strong> {booking.id}</p>
          <p><strong>Seats:</strong> {booking.seats.join(', ')}</p>
        </div>

        <div className="card" style={{ background: '#e3f2fd', border: '2px solid #2196f3', marginBottom: '20px' }}>
          <h3 style={{ color: '#1976d2', marginBottom: '15px' }}>Live Status</h3>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', marginBottom: '20px' }}>
            <div>
              <h4 style={{ fontSize: '14px', marginBottom: '5px' }}>Current Location</h4>
              <p style={{ margin: '0', fontSize: '18px', fontWeight: 'bold', color: '#1976d2' }}>
                📍 {busLocation.currentLocation}
              </p>
            </div>
            <div>
              <h4 style={{ fontSize: '14px', marginBottom: '5px' }}>Next Stop</h4>
              <p style={{ margin: '0', fontSize: '16px', fontWeight: 'bold' }}>
                🎯 {busLocation.nextStop}
              </p>
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px', marginBottom: '20px' }}>
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#1976d2' }}>{busLocation.speed}</div>
              <div style={{ fontSize: '12px', color: '#666' }}>Speed (km/h)</div>
            </div>
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#1976d2' }}>{busLocation.progress}%</div>
              <div style={{ fontSize: '12px', color: '#666' }}>Journey Progress</div>
            </div>
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#1976d2' }}>{estimatedArrival}</div>
              <div style={{ fontSize: '12px', color: '#666' }}>Est. Arrival</div>
            </div>
          </div>

          <div style={{ marginBottom: '15px' }}>
            <h4 style={{ fontSize: '14px', marginBottom: '10px' }}>Journey Progress</h4>
            <div style={{ backgroundColor: '#ddd', borderRadius: '10px', height: '20px', overflow: 'hidden' }}>
              <div 
                style={{ 
                  backgroundColor: '#2196f3', 
                  height: '100%', 
                  width: `${busLocation.progress}%`,
                  transition: 'width 0.5s ease'
                }}
              ></div>
            </div>
          </div>
        </div>

        <div className="card">
          <h3>Route Waypoints</h3>
          <div style={{ position: 'relative', paddingLeft: '30px' }}>
            {busLocation.waypoints.map((waypoint, index) => (
              <div key={index} style={{ 
                display: 'flex', 
                alignItems: 'flex-start', 
                marginBottom: '20px',
                position: 'relative'
              }}>
                <div style={{
                  position: 'absolute',
                  left: '-30px',
                  width: '20px',
                  height: '20px',
                  borderRadius: '50%',
                  backgroundColor: waypoint.status === 'Current' ? '#2196f3' : 
                                   waypoint.status === 'Passed' ? '#4caf50' : 
                                   waypoint.status === 'Destination' ? '#ff9800' : '#ccc',
                  border: '2px solid white',
                  boxShadow: '0 2px 4px rgba(0,0,0,0.2)'
                }}></div>

                {index < busLocation.waypoints.length - 1 && (
                  <div style={{
                    position: 'absolute',
                    left: '-21px',
                    top: '20px',
                    width: '2px',
                    height: 'calc(100% + 10px)',
                    backgroundColor: waypoint.status === 'Passed' ? '#4caf50' : '#ddd'
                  }}></div>
                )}

                <div style={{ flex: 1 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h4 style={{ margin: '0', fontSize: '14px' }}>{waypoint.location}</h4>
                    <span style={{ 
                      fontSize: '12px', 
                      color: '#666',
                      fontWeight: waypoint.status === 'Current' ? 'bold' : 'normal'
                    }}>
                      {waypoint.time}
                    </span>
                  </div>
                  <span style={{ 
                    fontSize: '11px', 
                    color: waypoint.status === 'Current' ? '#2196f3' : '#666',
                    fontWeight: waypoint.status === 'Current' ? 'bold' : 'normal'
                  }}>
                    {waypoint.status}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="card" style={{ background: '#fff3cd', border: '1px solid #ffeaa7' }}>
          <h4 style={{ color: '#856404', marginBottom: '10px' }}>Emergency Contacts</h4>
          <div style={{ display: 'flex', gap: '10px' }}>
            <button className="btn" onClick={handleCallDriver} style={{ backgroundColor: '#28a745' }}>
              📞 Call Driver
            </button>
            <button className="btn btn-secondary" onClick={handleEmergencyContact}>
              🆘 Emergency Help
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BusTracking;
